// Receive input from the executeWorkflowTrigger.
// Supports both direct named-field mapping (workflowInputs) and JSON-wrapped formats.
const raw = $('Start').first().json;

let inp;
if (raw.userMessage !== undefined || raw.systemPrompt !== undefined) {
  // Modern: named fields directly on json
  inp = raw;
} else if (typeof raw.input === 'string') {
  // Legacy: single JSON string wrapped under 'input'
  try { inp = JSON.parse(raw.input); } catch(e) { inp = {}; }
} else {
  inp = raw;
}

return {
  systemPrompt: inp.systemPrompt || '',
  RequestInput: { input: inp.userMessage || '' },
  ChannelInformation: {
    ChannelID: inp.channelId || null,
    MessageID: inp.messageId || null
  },
  InputType: inp.inputType || 'text'
};

const url = (typeof query === 'object' ? query.url || query : query).trim();
try {
  const res = await $helpers.request({ method: 'GET', url: 'https://r.jina.ai/' + url, headers: { 'Accept': 'text/plain' }, timeout: 15000 });
  const text = typeof res === 'string' ? res : JSON.stringify(res);
  return text.length > 4000 ? text.substring(0, 4000) + '\n\n[Content truncated at 4000 chars]' : text;
} catch(e) {
  return 'Error fetching URL: ' + e.message;
}

