SELECT id, title, details, category, priority, due_date, completed, project_id, created_at 
FROM tasks 
WHERE channel_id = {{ $('SetVars').first().json.ChannelInformation.ChannelID }}
AND completed = FALSE
ORDER BY due_date ASC NULLS LAST, priority DESC;

SELECT id, task_id, title, completed 
FROM subtasks 
WHERE task_id = {{ $fromAI('task_id', 'The parent task ID') }}
AND completed = FALSE;

INSERT INTO subtasks (task_id, title, completed)
VALUES (
    {{ $fromAI('task_id', 'Parent task ID') }},
    '{{ $fromAI('title', 'Subtask title') }}',
    {{ $fromAI('completed', 'Boolean, default false') }}
)
ON CONFLICT (task_id, title) DO UPDATE SET
    completed = EXCLUDED.completed
RETURNING id;

SELECT r.id, r.message, r.remind_at, r.task_id, r.subtask_id
FROM reminders r
WHERE r.channel_id = {{ $('SetVars').first().json.ChannelInformation.ChannelID }}
AND r.sent = FALSE
AND r.remind_at > NOW()
ORDER BY r.remind_at ASC;

SELECT id, name, description, status, due_date, created_at
FROM projects
WHERE channel_id = {{ $('SetVars').first().json.ChannelInformation.ChannelID }}
AND status != 'completed'
ORDER BY due_date ASC NULLS LAST;

