const fs = require('fs');
const path = require('path');
const keyword = query.trim().toLowerCase();
const vaultRoot = '/data/vault';
const matches = [];

function walk(dir) {
  let entries;
  try { entries = fs.readdirSync(dir, { withFileTypes: true }); } catch(e) { return; }
  for (const entry of entries) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      walk(full);
    } else if (entry.name.endsWith('.md')) {
      try {
        const text = fs.readFileSync(full, 'utf8');
        if (text.toLowerCase().includes(keyword) || entry.name.toLowerCase().includes(keyword)) {
          matches.push(full.replace(vaultRoot + '/', ''));
        }
      } catch(e) {}
    }
    if (matches.length >= 20) return;
  }
}

walk(vaultRoot);
return matches.length > 0 ? matches.join('\n') : 'No matching notes found.';

const fs = require('fs');
const path = require('path');

let params;
if (typeof query === 'object' && query !== null) {
  params = query;
} else {
  try { params = JSON.parse(query); } catch(e) { return 'Error: could not parse input. Expected JSON with path and content fields.'; }
}

const notePath = (params.path || '').trim();
const noteContent = (params.content || '').trim();
const tags = Array.isArray(params.tags) ? params.tags : [];

if (!notePath.startsWith('Atlas/Baxter/')) {
  return 'Error: WriteVaultNote can only write to Atlas/Baxter/. Path must start with Atlas/Baxter/.';
}
if (!notePath.endsWith('.md')) {
  return 'Error: path must end with .md';
}
if (!noteContent) {
  return 'Error: content is required.';
}

const fullPath = '/data/vault/' + notePath;
const dir = path.dirname(fullPath);
fs.mkdirSync(dir, { recursive: true });

const now = new Date().toISOString().split('T')[0];
const tagLine = tags.length > 0 ? '\ntags: [' + tags.join(', ') + ']' : '';
const frontmatter = '---\ncreated_by: baxter\ndate: ' + now + tagLine + '\n---\n\n';

const finalContent = frontmatter + noteContent;
fs.writeFileSync(fullPath, finalContent, 'utf8');
return 'Note saved to ' + notePath;

let vars = $('SetVars').first().json;
let rawOutput = $('Agent').first().json.output ?? "";

const cleanResponse = (input) => {
    if (!input || typeof input !== "string") return "";
    let output = input.replace(/\\n/g, "\n");
    output = output.replace(/<think>[\s\S]*?<\/think>/gi, "");
    output = output.replace(/<think>[\s\S]*/gi, "");
    output = output.replace(/<\|channel>thought[\s\S]*?<channel\|>/gi, "");
    output = output.replace(/<\|channel>thought[\s\S]*/gi, "");
    output = output.trim();
    const matches = [...output.matchAll(/RESPONSE:\s*/g)];
    if (matches.length > 0) {
        const last = matches[matches.length - 1];
        const extracted = output.slice(last.index + last[0].length).trim();
        if (extracted.length > 0) return extracted.slice(0, 3000) + (extracted.length > 3000 ? "..." : "");
    }
    const reasoningPatterns = [
        /^(okay|ok|alright|right|so|well)[,\s]/i,/^let me\s/i,
        /^i('ll| will| need to| should| must| can| am going to)\s/i,
        /^i('ve| have) (retrieved|fetched|found|got|collected)/i,
        /^now i('ll| need| should| will| can)/i,
        /^(first|now|next|then|finally)[,\s]/i,
        /^the user[\s(wants|asked|needs)]/i,
        /^they (want|asked|need|said)/i,
        /^(looking at|checking|reviewing|analyzing|considering)/i,
        /^(since|given that|because|as)\s/i,
        /^(therefore|thus|so|hence)\s/i,
        /^my (response|answer|plan|approach)/i,
        /^let me (format|organize|structure|present|summarize|summarise)/i,
        /^here('s| is) (a summary|the|what)/i,
        /^this (seems|looks|appears|is a)/i,
        /^it (seems|looks|appears)/i,
        /^(OUTPUT:|##OUTPUT|Start your final answer|\/no_think)/i,
    ];
    const lines = output.split("\n").map(l => l.trim()).filter(Boolean);
    const responseLines = lines.filter(l => !reasoningPatterns.some(p => p.test(l)));
    const result = (responseLines.length > 0 ? responseLines : [lines[lines.length - 1] || ""]).join("\n").trim();
    return result.slice(0, 3000) + (result.length > 3000 ? "..." : "");
};

let response = cleanResponse(rawOutput);
if (!response || response.trim().length === 0) {
    response = "Sorry, I ran into an issue formulating a response. Please try again.";
}

return {
    ...vars,
    AgentOutput: {
        response,
        model: null,
        tokens: { prompt: null, completion: null, total: null },
        metadata: {}
    }
};
